// ─── FIRESTORE HELPERS ─────────────────────────────────────────────────────────
// All data is stored in a single document: /agency/data
// This keeps reads/writes minimal and atomic for a single-user app.
const DATA_REF = () => doc(firebaseDB, "agency", "data");

async function loadFromFirestore() {
  try {
    const snap = await getDoc(DATA_REF());
    if (snap.exists()) return snap.data();
  } catch (e) { console.warn("Firestore load error:", e); }
  return null;
}

async function saveToFirestore(data) {
  try {
    await setDoc(DATA_REF(), data);
  } catch (e) { console.warn("Firestore save error:", e); }
}

