// ─── STORAGE HOOK (Firestore-backed) ──────────────────────────────────────────
function useStore() {
  const [products, setProductsRaw] = useState(INITIAL_PRODUCTS);
  const [sales, setSalesRaw] = useState([]);
  const [stockLogs, setStockLogsRaw] = useState([]);
  const [udhar, setUdharRaw] = useState([]);
  const [expenses, setExpensesRaw] = useState([]);
  const [buyPriceHistory, setBuyPriceHistoryRaw] = useState([]);
  const [invoiceCounter, setInvoiceCounterRaw] = useState(1001);
  const [storeReady, setStoreReady] = useState(false);

  // Keep a ref to the latest state so we can build the save payload
  const stateRef = useRef({});
  stateRef.current = { products, sales, stockLogs, udhar, expenses, buyPriceHistory, invoiceCounter };

  // Load once from Firestore on mount
  useEffect(() => {
    loadFromFirestore().then(data => {
      if (data) {
        if (data.products)          setProductsRaw(data.products);
        if (data.sales)             setSalesRaw(data.sales);
        if (data.stockLogs)         setStockLogsRaw(data.stockLogs);
        if (data.udhar)             setUdharRaw(data.udhar);
        if (data.expenses)          setExpensesRaw(data.expenses);
        if (data.buyPriceHistory)   setBuyPriceHistoryRaw(data.buyPriceHistory);
        if (data.invoiceCounter)    setInvoiceCounterRaw(data.invoiceCounter);
      }
      setStoreReady(true);
    });
  }, []);

  // Save status — "idle" | "saving" | "saved" | "error"
  const [saveStatus, setSaveStatus] = useState("idle");
  const pendingPatch = useRef({});
  const saveTimer = useRef(null);
  const isSaving = useRef(false);

  const scheduleSave = (patch) => {
    pendingPatch.current = { ...pendingPatch.current, ...patch };
    clearTimeout(saveTimer.current);
    setSaveStatus("saving");
    saveTimer.current = setTimeout(async () => {
      if (isSaving.current) return;
      isSaving.current = true;
      const toSave = { ...stateRef.current, ...pendingPatch.current };
      pendingPatch.current = {};
      let retries = 3;
      while (retries > 0) {
        try {
          await saveToFirestore(toSave);
          setSaveStatus("saved");
          setTimeout(() => setSaveStatus("idle"), 2000);
          break;
        } catch (e) {
          retries--;
          if (retries === 0) {
            setSaveStatus("error");
            // Re-queue failed patch for next attempt
            pendingPatch.current = { ...toSave };
          } else {
            await new Promise(r => setTimeout(r, 1500));
          }
        }
      }
      isSaving.current = false;
    }, 800);
  };

  // Warn user if unsaved data exists on page close
  useEffect(() => {
    const handler = (e) => {
      if (saveStatus === "saving" || Object.keys(pendingPatch.current).length > 0) {
        e.preventDefault();
        e.returnValue = "";
      }
    };
    window.addEventListener("beforeunload", handler);
    return () => window.removeEventListener("beforeunload", handler);
  }, [saveStatus]);

  const setProducts = v => {
    const d = typeof v === "function" ? v(stateRef.current.products) : v;
    stateRef.current = { ...stateRef.current, products: d };
    setProductsRaw(d); scheduleSave({ products: d });
  };
  const setSales = v => {
    const d = typeof v === "function" ? v(stateRef.current.sales) : v;
    stateRef.current = { ...stateRef.current, sales: d };
    setSalesRaw(d); scheduleSave({ sales: d });
  };
  const setStockLogs = v => {
    const d = typeof v === "function" ? v(stateRef.current.stockLogs) : v;
    stateRef.current = { ...stateRef.current, stockLogs: d };
    setStockLogsRaw(d); scheduleSave({ stockLogs: d });
  };
  const setUdhar = v => {
    const d = typeof v === "function" ? v(stateRef.current.udhar) : v;
    stateRef.current = { ...stateRef.current, udhar: d };
    setUdharRaw(d); scheduleSave({ udhar: d });
  };
  const setExpenses = v => {
    const d = typeof v === "function" ? v(stateRef.current.expenses) : v;
    stateRef.current = { ...stateRef.current, expenses: d };
    setExpensesRaw(d); scheduleSave({ expenses: d });
  };
  const setBuyPriceHistory = v => {
    const d = typeof v === "function" ? v(stateRef.current.buyPriceHistory) : v;
    stateRef.current = { ...stateRef.current, buyPriceHistory: d };
    setBuyPriceHistoryRaw(d); scheduleSave({ buyPriceHistory: d });
  };
  const setInvoiceCounter = v => {
    const d = typeof v === "function" ? v(stateRef.current.invoiceCounter) : v;
    stateRef.current = { ...stateRef.current, invoiceCounter: d };
    setInvoiceCounterRaw(d); scheduleSave({ invoiceCounter: d });
  };

  return { products, setProducts, sales, setSales, stockLogs, setStockLogs, udhar, setUdhar, expenses, setExpenses, buyPriceHistory, setBuyPriceHistory, invoiceCounter, setInvoiceCounter, storeReady, saveStatus };
}

