// ── Public API ──
const authService = {
  async signIn(username, password) {
    try {
      const email = username;
      const cred = await signInWithEmailAndPassword(firebaseAuth, email, password);
      return { success: true, user: { uid: cred.user.uid, username, role: "owner", displayName: username } };
    } catch (e) {
      return { success: false, error: "Invalid username or password." };
    }
  },

  async signOut() { await fbSignOut(firebaseAuth); },

  async getSession() {
    return new Promise(resolve => {
      onAuthStateChanged(firebaseAuth, user => {
        resolve(user ? { uid: user.uid, username: user.email, role: "owner", displayName: user.displayName || "Admin" } : null);
      });
    });
  },
};

// ─── useAuth HOOK ──────────────────────────────────────────────────────────────
// Centralizes all auth state. Components call this instead of touching localStorage.
//
// FIREBASE REPLACEMENT: Replace getSession() polling with onAuthStateChanged:
//   useEffect(() => {
//     const unsubscribe = onAuthStateChanged(firebaseAuth, firebaseUser => {
//       setUser(firebaseUser ? { uid: firebaseUser.uid, ... } : null);
//       setLoading(false);
//     });
//     return unsubscribe;
//   }, []);
function useAuth() {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  // Restore session on mount
  // FIREBASE: replace this block with onAuthStateChanged listener
  const [_sessionChecked] = useState(() => {
    authService.getSession().then(u => { setUser(u); setLoading(false); });
    return true;
  });

  const signIn = async (username, password) => {
    const result = await authService.signIn(username, password);
    if (result.success) setUser(result.user);
    return result;
  };

  const signOut = async () => {
    await authService.signOut();
    setUser(null);
  };

  return { user, loading, signIn, signOut, isAuthenticated: !!user };
}

